[{"operationName":"teamPage","variables":{"id":12864719},"query":"query teamPage($id: Int!) {
  team(id: $id) {
    id
    name
    number
    isTied
    standing
    division {
      id
      name
      number
      timeOfPlay
      nightOfPlay
      format
      state
      isTournament
      tournament {
        id
        name
        __typename
      }
      __typename
    }
    location {
      id
      name
      address {
        id
        name
        __typename
      }
      __typename
    }
    session {
      id
      name
      __typename
    }
    league {
      id
      slug
      __typename
    }
    __typename
  }
}
"}]

[{"operationName":"LeagueBox","variables":{"id":894},"query":"query LeagueBox($id: Int!) {
  viewer {
    __typename
    id
    firstName
    lastName
    emailAddress
  }
  league(id: $id) {
    id
