}
"},{"operationName":"DivisionContacts","variables":{"id":417530},"query":"query DivisionContacts($id: Int!) {
  division(id: $id) {
    id
    name
    contacts {
      phone
      alias {
        id
        displayName
        __typename
      }
      __typename
    }
    __typename
  }
}
"},{"operationName":"teamRoster","variables":{"id":12864719},"query":"query teamRoster($id: Int!) {
  team(id: $id) {
    ...rosterComponent
    __typename
  }
}

fragment rosterComponent on Team {
  id
  name
  number
  league {
    id
    slug
    __typename
  }
  division {
    id
    type
    __typename
  }
  roster {
    id
    memberNumber
    displayName
    matchesWon
    matchesPlayed
    ... on EightBallPlayer {
      pa
      ppm
      skillLevel
      __typename
    }
    ... on NineBallPlayer {
      pa
      ppm
      skillLevel
      __typename
    }
    member {
      id
      __typename
    }
    __typename
  }
  __typename
}
"},{"operationName":"teamSchedule","variables":{"id":12864719},"query":"query teamSchedule($id: Int!) {
  team(id: $id) {
    id
    sessionBonusPoints
    sessionPoints
    sessionTotalPoints
    division {
      id
      isTournament
      __typename
    }
    matches(unscheduled: true) {
      week
      type
      ...matchListItem
      __typename
    }
    __typename
  }
}

fragment matchListItem on Match {
  id
  isBye
  status
  scoresheet
  startTime
  isMine
  isPaid
  isScored
  isFinalized
  isPlayoff
  description
  tableNumber
  results {
    homeAway
    points {
      total
      __typename
    }
    __typename
  }
  timeZone {
    id
    name
    __typename
  }
  location {
    id
    name
    address {
      id
      name
      __typename
    }
    __typename
  }
  home {
    id
    name
    number
    isMine
    __typename
  }
  away {
    id
    name
    number
    isMine
    __typename
  }
  league {
    id
    isMine
    slug
    isElectronicPaymentsEnabled
    __typename
  }
  orderItems {
    id
    order {
      id
      member {
        id
        firstName
        lastName
        __typename
      }
      __typename
    }
    __typename
  }
  division {
    id
    scheduleInEdit
    isTournament
    __typename
  }
  __typename
}
"}]
